window.VBPStoreHistoryHelpers={pushHistory:function(t,e,i,s){var r={state:JSON.stringify(e),description:s||"Cambio",timestamp:Date.now()};t.past.push(r),t.future=[],t.past.length>i&&t.past.shift()},undo:function(t,e){if(!t.past.length)return null;var i=t.past.pop(),s={state:JSON.stringify(e),description:i.description,timestamp:Date.now()};t.future.unshift(s);var r="string"==typeof i?i:i.state;return{elements:JSON.parse(r),description:i.description||"Cambio"}},redo:function(t,e){if(!t.future.length)return null;var i=t.future.shift(),s={state:JSON.stringify(e),description:i.description,timestamp:Date.now()};t.past.push(s);var r="string"==typeof i?i:i.state;return{elements:JSON.parse(r),description:i.description||"Cambio"}}};